def __setitem__(self, column_name: str, feature: FeatureType):
    super().__setitem__(column_name, feature)

@keep_features_dicts_synced
def __delitem__(self, column_name: str):
    super().__delitem__(column_name)

@keep_features_dicts_synced
def update(self, iterable, **kwds):
    # We need to deep-merge the existing and new values when both are (nested) dictionaries, so that updating a
    # feature only overrides the specified sub-fields instead of replacing the whole nested structure.
    if hasattr(iterable, "keys"):
        for key in iterable.keys():
            self[key] = self._merge_or_set(key, iterable[key])
    else:
        for key, value in iterable:
            self[key] = self._merge_or_set(key, value)
    for key, value in kwds.items():
        self[key] = self._merge_or_set(key, value)

def _merge_or_set(self, key: str, value: FeatureType) -> FeatureType:
    if key in self:
        cur_value = self[key]
        if isinstance(cur_value, dict) and isinstance(value, dict):
            cur_value.update(value)
            return cur_value
        if (
            isinstance(cur_value, Sequence)
            and isinstance(value, Sequence)
            and isinstance(cur_value.feature, dict)
            and isinstance(value.feature, dict)
        ):
            cur_value.feature.update(value.feature)
            return cur_value
    return value

